102	.skip-link {
103	  background: var(--amber);
104	  border: 1px solid var(--parchment);
105	  box-shadow: 0 0 0 2px var(--stone), var(--glow-sm);
106	  color: var(--stone);
107	  font-family: "IBM Plex Mono", monospace;
108	  font-size: 0.75rem;
109	  font-weight: 700;
110	  left: 1rem;
111	  letter-spacing: 0.12em;
112	  padding: 0.55rem 0.75rem;
113	  position: fixed;
114	  text-decoration: none;
115	  text-transform: uppercase;
116	  top: 0.75rem;
117	  transform: translateY(-160%);
118	  transition: transform 160ms ease;
119	  z-index: 10000;
120	}
