876	/* ── Gate (/) animations ─────────────────────────────────────────────────── */
877	
878	/* Idle state: the labyrinth rotates *slowly* (90s full turn) plus a subtle
879	   4s amber breath via drop-shadow intensity. The rotation is slow enough to
880	   feel like a ritual object, not a spinner. */
881	.gate-labyrinth {
882	  display: inline-block;
883	  animation: gate-spin-slow 90s linear infinite;
884	  color: var(--amber);
885	}
886	
887	.gate-pulse {
888	  animation: gate-spin-slow 90s linear infinite, gate-breath 4.5s ease-in-out infinite;
889	}
890	
891	/*
892	 * TRANSITION ANIMATION (login → dashboard) — minimalist rewrite
893	 * ─────────────────────────────────────────────────────────────
894	 * Two effects, no flash. Total ~300 ms:
895	 *
896	 *   1. `.gate-leave` on the form + wordmark + labyrinth:
897	 *        a 260 ms opacity + small translateY fade. The whole idle
898	 *        composition drifts down a hair and dims to zero. Ease-out so
899	 *        the motion settles rather than ending abruptly.
900	 *
901	 *   2. `.gate-hairline` (a thin amber line centred in the viewport via
902	 *      a flex wrapper in Gate.tsx):
903	 *        materialises at zero width, expands horizontally from the
904	 *        centre to full viewport width over ~180 ms, holds a beat,
905	 *        fades out. The sweep itself is the transition's only active
906	 *        visual element — no colour flashes, no screen fill.
907	 *
908	 * Both start together when `phase` flips to `entering`, run in parallel
909	 * for ~300 ms, and leave the viewport empty at the moment the router
910	 * navigates. The dashboard side (`.codex-arrival` +
911	 * `.codex-arrival-hairline`) mirrors the effect in reverse: the
912	 * hairline contracts back to centre while content fades up.
913	 *
914	 * Prior revision removed: a three-layer ignition with radial amber
915	 * shockwave (`.gate-flash`), rotating conic sunburst (`.gate-rays`),
916	 * and 9× scale / 1800° rotation on the hero (`.gate-open`). The
917	 * amber flash was visually loud and the most-complained-about detail.
918	 */
919	
920	@keyframes gate-spin-slow {
921	  from { transform: rotate(0deg); }
922	  to { transform: rotate(360deg); }
923	}
924	
925	@keyframes gate-breath {
926	  0%, 100% { filter: drop-shadow(0 0 10px var(--amber-glow)); }
927	  50% { filter: drop-shadow(0 0 20px var(--amber-glow)) drop-shadow(0 0 4px var(--amber)); }
928	}
929	
930	/* Shared exit for form + wordmark + labyrinth. Tiny down-drift so the
931	   whole composition settles away together rather than each piece
932	   falling independently. */
933	.gate-leave {
934	  animation: gate-leave 0.26s cubic-bezier(0.33, 0, 0.67, 1) forwards;
935	}
936	
937	@keyframes gate-leave {
938	  0%   { opacity: 1; transform: translateY(0); }
939	  100% { opacity: 0; transform: translateY(10px); }
940	}
941	
942	/* Horizon hairline. Painted directly (no gradient) with an amber glow
943	   from box-shadow. The wrapper in Gate.tsx is
944	   `display: grid; place-items: center`, so as `width` expands from
945	   zero the bar grows symmetrically outward from the viewport centre.
946	   On fast machines this runs entirely on the compositor thread. */
947	.gate-hairline {
948	  width: 0;
949	  height: 1px;
950	  background: var(--amber);
951	  box-shadow:
952	    0 0 6px var(--amber),
953	    0 0 18px var(--amber-glow);
954	  animation: gate-hairline 0.3s cubic-bezier(0.22, 0.61, 0.36, 1) forwards;
955	}
956	
957	@keyframes gate-hairline {
958	  0%   { width: 0;     opacity: 0; }
959	  15%  { width: 0;     opacity: 1; }
960	  55%  { width: 100vw; opacity: 1; }
961	  100% { width: 100vw; opacity: 0; }
962	}
963	
964	/* ── Arrival animation (dashboard side of the entrance) ─────────────────
965	 * The EntranceWelcome client component picks up the `codex:just-entered`
966	 * sessionStorage flag set by the Gate and, if present, mounts
967	 * `.codex-arrival` on the page wrapper for ~280 ms plus a mirrored
968	 * `.codex-arrival-hairline` that contracts back to the centre.
969	 *
970	 * Content fades up from a small downward offset — a quiet reveal,
971	 * no blur, no scale, no brightness pump. The whole page is visible
972	 * and fully interactive within 300 ms of navigation. */
973	.codex-arrival {
974	  animation: codex-arrival-fade 0.28s cubic-bezier(0.22, 0.61, 0.36, 1) forwards;
975	}
976	
977	@keyframes codex-arrival-fade {
978	  0%   { opacity: 0; transform: translateY(8px); }
979	  100% { opacity: 1; transform: translateY(0); }
980	}
981	
982	/* Mirrored hairline that the dashboard paints on arrival — starts
983	   at full viewport width and contracts back to a zero-width pinpoint
984	   at the centre, then fades. Same visual vocabulary as the exit,
985	   reversed. */
986	.codex-arrival-hairline {
987	  width: 100vw;
988	  height: 1px;
989	  background: var(--amber);
990	  box-shadow:
991	    0 0 6px var(--amber),
992	    0 0 18px var(--amber-glow);
993	  animation: codex-arrival-hairline 0.32s cubic-bezier(0.33, 0, 0.67, 1) forwards;
994	}
995	
996	@keyframes codex-arrival-hairline {
997	  0%   { width: 100vw; opacity: 1; }
998	  55%  { width: 40vw;  opacity: 0.8; }
999	  100% { width: 0;     opacity: 0; }
1000	}
1001	
1002	@media (prefers-reduced-motion: reduce) {
1003	  .gate-leave,
1004	  .gate-hairline,
1005	  .codex-arrival,
1006	  .codex-arrival-hairline { animation: none !important; }
1007	}
