 * The upload form is unusually tall (file drop, title, description,
 * type, visibility toggles, blog fields) and with the default
 * `verticalAnchor="center"` a backdrop sits directly behind the
 * mid-form region and reads as "concealed". Two small overrides:
 *
 *   verticalAnchor="top" + offsetY=-48
 *       Pins the figure to the top of the 80vh column and lifts it a
 *       further 48 px so the head sits nearer the page header instead
 *       of level with the form's fieldset.
 *
 *   offsetX=-96
 *       Shifts the figure 96 px to the left. Combined with the fade
 *       mask (which tracks the offset — see SculptureBackdrop) this
 *       pushes the figure's right edge well clear of the form's input
 *       column; `overflow: hidden` on the outer wrapper clips the part
 *       that leaves the viewport cleanly.
 *
 * The numbers were tuned against a 1440-wide viewport; on anything
 * narrower the SculptureBackdrop hides itself via its 768 px breakpoint.
 */
export default async function UploadPage() {
  const tenant = await requireTenantContext();
  if (!tenant) return null;
  // Viewers reach this page if they bookmark it (the nav link is
  // hidden for them, but the URL is open). Render an explanatory
  // notice instead of the form so a wandering viewer understands
  // why the page is empty rather than blaming a broken form. The
  // /api/upload* endpoints also reject viewers, so even if the form
  // somehow got rendered, no upload would land.
  if (!canWrite(tenant.role)) {
    return (
      <main
        style={{
          maxWidth: "640px",
          margin: "0 auto",
          padding: "4rem 2rem",
          textAlign: "center",
        }}
      >
        <h1
          style={{
            fontFamily: "'Cinzel Decorative', 'Cinzel', serif",
            fontSize: "1.6rem",
            letterSpacing: "0.18em",
            color: "var(--amber)",
            textShadow: "var(--glow-md)",
            margin: 0,
          }}
        >
          Dedicatio
        </h1>
        <p
          className="mono"
          style={{
            fontSize: "0.62rem",
            letterSpacing: "0.28em",
            textTransform: "uppercase",
            color: "var(--amber-dim)",
            marginTop: "0.5rem",
          }}
        >
          Read-only account
        </p>
        <p
          style={{
            fontFamily: "'EB Garamond', serif",
            fontSize: "1.05rem",
            color: "var(--parchment-dim)",
            marginTop: "2rem",
            lineHeight: 1.65,
          }}
        >
          Your account can read everything in the firm&apos;s Codex but
          cannot upload new material. Ask an admin in your organisation
          to upgrade you to <strong>founder</strong> if you need to
          contribute transcripts, sessions, or essays.
        </p>
      </main>
    );
  }
  return (
    <div style={{ position: "relative", overflow: "hidden", minHeight: "80vh" }}>
      <SculptureBackdrop
        src="/sculptures/augustus.mesh.bin"
        side="left"
        yawSpeed={0.018}
        verticalAnchor="top"
        offsetY={-48}
        offsetX={-96}
      />
      <div style={{ position: "relative", zIndex: 1 }}>
        <UploadForm />
      </div>
    </div>
  );
}

