                  {u.status === "ingested" ? (
                    <PublishToggle
                      uploadId={u.id}
                      initialPublishedAt={u.publishedAt}
                      initialSlug={u.slug}
                    />
                  ) : null}
                </div>
              </div>
            </div>
          ))
        )}
      </div>
    </section>
  );
}

