            <ForecastsPulse tenant={tenant} />
          </Suspense>
        </div>
        <Suspense fallback={null}>
          <AttentionSignals tenant={tenant} />
        </Suspense>
        <Suspense fallback={null}>
          <UploadWorkStatus tenant={tenant} />
        </Suspense>
        <Suspense fallback={null}>
