            {display.map((c) => (
              <li
                key={c.id}
                className="portal-card"
                style={{ padding: "1rem 1.25rem" }}
              >
                <Link
                  href={`/conclusions/${c.id}`}
                  style={{
                    textDecoration: "none",
                    color: "inherit",
                    display: "flex",
                    gap: "0.9rem",
