                >
                  <ConfidenceTierSigil tier={c.confidenceTier} />
                  <div style={{ minWidth: 0, flex: 1 }}>
                    <div
                      className="mono"
                      style={{
                        fontSize: "0.62rem",
                        color: "var(--amber-dim)",
                        textTransform: "uppercase",
                        letterSpacing: "0.12em",
                      }}
                    >
                      {c.confidenceTier}
                      {c.topicHint ? ` · ${c.topicHint}` : ""}
                      {c.attributedFounder
                        ? ` · ${founderDisplayName(c.attributedFounder)}`
                        : ""}
                    </div>
                    <p
                      style={{
                        marginTop: "0.5rem",
                        color: "var(--parchment)",
                      }}
                    >
                      {c.text}
                    </p>
                    {c.rationale && (
                      <p
                        style={{
                          marginTop: "0.35rem",
                          fontSize: "0.8rem",
                          color: "var(--parchment-dim)",
                        }}
                      >
                        {c.rationale}
                      </p>
                    )}
                  </div>
                </Link>
              </li>
            ))}
          </ul>
        )}

        {display.length > 0 && (
          <div
            style={{
              display: "flex",
              justifyContent: "space-between",
              alignItems: "center",
              marginTop: "1.5rem",
              padding: "0.75rem 0",
              borderTop: "1px solid var(--border)",
            }}
          >
            <span style={{ fontSize: "0.7rem", color: "var(--parchment-dim)" }}>
              {total} conclusion{total !== 1 ? "s" : ""} · page {page}
            </span>
            <div style={{ display: "flex", gap: "0.5rem" }}>
              {page > 1 && (
                <Link
                  href={buildPageUrl(page - 1)}
                  className="btn"
                  style={{ fontSize: "0.65rem", textDecoration: "none" }}
                >
                  ← Previous
                </Link>
              )}
              {hasNext && (
                <Link
                  href={buildPageUrl(page + 1)}
                  className="btn"
                  style={{ fontSize: "0.65rem", textDecoration: "none" }}
                >
                  Next →
                </Link>
              )}
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

