              color: "var(--amber)",
              textShadow: "var(--glow-sm)",
              margin: 0,
            }}
          >
            Conclusiones
          </h1>
          <p
            className="mono"
            style={{
              fontSize: "0.62rem",
              letterSpacing: "0.28em",
              textTransform: "uppercase",
              color: "var(--amber-dim)",
              margin: "0.25rem 0 0",
            }}
          >
            The firm&apos;s canon · Discobolus, MSR
          </p>
          <p
            style={{
              fontFamily: "'EB Garamond', serif",
              fontStyle: "italic",
              fontSize: "1rem",
              color: "var(--parchment-dim)",
              marginTop: "0.55rem",
              marginBottom: 0,
              lineHeight: 1.55,
              maxWidth: "44em",
            }}
          >
            The discus thrower is captured in resolved motion. Conclusions
            here are the firm&apos;s equivalent: commitments that move
            deliberation from potential to action.
          </p>
        </header>

        <form
          action={basePath}
          method="get"
          style={{ display: "flex", gap: "0.5rem", marginBottom: "1rem", flexWrap: "wrap" }}
        >
          {basePath === "/knowledge" ? (
            <input type="hidden" name="tab" value="conclusions" />
          ) : null}
          <input
            type="text"
            name="q"
            defaultValue={q}
            placeholder="Search conclusions…"
            style={{
              flex: 1,
              minWidth: "12rem",
              maxWidth: "24rem",
              padding: "0.4rem 0.75rem",
              fontSize: "0.8rem",
              fontFamily: "inherit",
              background: "transparent",
