                  : {}),
              }}
            >
              <ConfidenceTierSigil tier={t} size="0.55rem" />
              <span>{t}</span>
            </Link>
          ))}
          <Link
            href={buildTopicUrl("method")}
            className="btn"
            style={{ fontSize: "0.7rem", textDecoration: "none" }}
          >
            topic: method
          </Link>
        </div>

        {display.length === 0 ? (
          <div
            className="ascii-frame"
            data-label="VACUUM · EMPTY"
            style={{ padding: "2rem 1rem", textAlign: "center" }}
